const data = $json.data;

const title = data.title || 'Untitled Video';
const summary = data.summary || 'No summary available.';
const tags = (data.tags || []).join(' ');
const videoUrl = $('🎬 Submit Video for Summary').item.json.body?.video_url || $('Chat Message').item.json.chatInput || '';

// Build highlights section
let highlightsHtml = '';
if (data.highlights && data.highlights.length > 0) {
  for (const h of data.highlights) {
    const startSec = Math.floor(h.start / 1000);
    const endSec = Math.floor(h.end / 1000);
    const mins = m => Math.floor(m / 60);
    const secs = m => m % 60;
    const timeLabel = `${String(mins(startSec)).padStart(2,'0')}:${String(secs(startSec)).padStart(2,'0')} - ${String(mins(endSec)).padStart(2,'0')}:${String(secs(endSec)).padStart(2,'0')}`;

    let eventsHtml = '';
    if (h.events && h.events.length > 0) {
      eventsHtml = '<ul style="margin:4px 0 0 0; padding-left:18px;">';
      for (const e of h.events) {
        const eSec = Math.floor(e.timestamp / 1000);
        const eTime = `${String(mins(eSec)).padStart(2,'0')}:${String(secs(eSec)).padStart(2,'0')}`;
        eventsHtml += `<li style="color:#555; font-size:13px; margin-bottom:3px;">[${eTime}] ${e.desc}</li>`;
      }
      eventsHtml += '</ul>';
    }

    highlightsHtml += `
      <div style="border-left:3px solid #4A90E2; padding:8px 12px; margin-bottom:12px; background:#f9f9f9; border-radius:0 6px 6px 0;">
        <p style="margin:0 0 4px 0; font-weight:600; color:#1a1a1a; font-size:14px;">${h.desc}</p>
        <p style="margin:0 0 4px 0; color:#888; font-size:12px;">${timeLabel}</p>
        ${eventsHtml}
      </div>`;
  }
}

const emailBody = `
<div style="font-family:Arial,sans-serif; max-width:640px; margin:0 auto;">

  <div style="background:#4A90E2; padding:20px 24px; border-radius:8px 8px 0 0;">
    <h2 style="margin:0; color:#fff; font-size:20px;">Competitor Video Analysis</h2>
    <p style="margin:4px 0 0 0; color:#dce8f8; font-size:13px;">Powered by WayinVideo + n8n</p>
  </div>

  <div style="border:1px solid #e0e0e0; border-top:none; padding:20px 24px; border-radius:0 0 8px 8px;">

    <h3 style="margin:0 0 6px 0; color:#1a1a1a;">${title}</h3>
    <p style="margin:0 0 16px 0;">
      <a href="${videoUrl}" style="color:#4A90E2; font-size:13px;">${videoUrl}</a>
    </p>

    <h4 style="margin:0 0 8px 0; color:#333; border-bottom:1px solid #eee; padding-bottom:6px;">Summary</h4>
    <p style="color:#444; line-height:1.6; margin:0 0 20px 0;">${summary}</p>

    <h4 style="margin:0 0 10px 0; color:#333; border-bottom:1px solid #eee; padding-bottom:6px;">Key Highlights</h4>
    ${highlightsHtml || '<p style="color:#888;">No highlights available.</p>'}

    <h4 style="margin:16px 0 8px 0; color:#333; border-bottom:1px solid #eee; padding-bottom:6px;">Hashtags</h4>
    <p style="color:#4A90E2; font-size:13px; margin:0;">${tags}</p>

  </div>

  <p style="color:#bbb; font-size:11px; text-align:center; margin-top:12px;">Generated by WayinVideo + n8n automation</p>
</div>
`;

return [{
  json: {
    subject: `Competitor Analysis: ${title}`,
    body: emailBody
  }
}];
